// // This module compares two 12-bit inputs, A and B, and outputs two single-bit signals: GT (Greater Than) and LT (Less Than). When A is less than B, the GT output will be high (1), and the LT output will be low (0). Conversely, when A is greater than B, the LT output will be high (1), and the GT output will be low (0).
module top_module(GT, LT, A, B);output GT;
   output LT;

   input  [11:0] A;
   input  [11:0] B;


   assign GT = A > B  ;
   assign LT = A < B  ;    


endmodule
